        using (var sha256 = SHA256.Create())
        {
            var hash = sha256.ComputeHash(Encoding.UTF8.GetBytes(data));
            var hashString = BitConverter.ToString(hash).Replace("-", "").Substring(0, 8);
            return $"***REDACTED-{hashString}***";
        }
    }

